import sys
input = sys.stdin.readline

def solve():
    n, m, q = map(int, input().split())
    locked = [[False]*(m+2) for _ in range(n+2)]

    f = [[0]*(m+2) for _ in range(n+2)]
    g = [[0]*(m+2) for _ in range(n+2)]

    total = 0
    for i in range(1, n+1):
        for j in range(1, m+1):
            f[i][j] = g[i][j-1] + 1
            g[i][j] = f[i-1][j] + 1
            total += f[i][j] + g[i][j] - 1

    def update_cell(i, j):
        nonlocal total
        if i < 1 or i > n or j < 1 or j > m:
            return False
        old_f = f[i][j]
        old_g = g[i][j]
        if locked[i][j]:
            f[i][j] = 0
            g[i][j] = 0
        else:
            f[i][j] = g[i][j-1] + 1
            g[i][j] = f[i-1][j] + 1
        total += (f[i][j] - old_f) + (g[i][j] - old_g)
        return f[i][j] != old_f or g[i][j] != old_g

    def propagate(i, j):
        # f[i][j] changed -> affects g[i+1][j] -> affects f[i+1][j+1] -> ...
        ci, cj = i+1, j
        next_is_g = True
        while 1 <= ci <= n and 1 <= cj <= m:
            if next_is_g:
                old = g[ci][cj]
                if locked[ci][cj]:
                    g[ci][cj] = 0
                else:
                    g[ci][cj] = f[ci-1][cj] + 1
                total += g[ci][cj] - old
                if g[ci][cj] == old:
                    break
                cj += 1
                next_is_g = False
            else:
                old = f[ci][cj]
                if locked[ci][cj]:
                    f[ci][cj] = 0
                else:
                    f[ci][cj] = g[ci][cj-1] + 1
                total += f[ci][cj] - old
                if f[ci][cj] == old:
                    break
                ci += 1
                next_is_g = True

    results = []
    for _ in range(q):
        x, y = map(int, input().split())
        locked[x][y] = not locked[x][y]
        changed = update_cell(x, y)
        if changed:
            # f[x][y] changed -> propagate down-right starting g[x+1][y]
            propagate(x, y)
            # g[x][y] changed -> propagate right-down starting f[x][y+1]
            # Simulate: g[x][y] -> f[x][y+1] -> g[x+1][y+1] -> ...
            ci, cj = x, y+1
            next_is_f = True
            while 1 <= ci <= n and 1 <= cj <= m:
                if next_is_f:
                    old = f[ci][cj]
                    if locked[ci][cj]:
                        f[ci][cj] = 0
                    else:
                        f[ci][cj] = g[ci][cj-1] + 1
                    total += f[ci][cj] - old
                    if f[ci][cj] == old:
                        break
                    ci += 1
                    next_is_f = False
                else:
